// Magnetic element with GSAP spring physics
function Magnetic({ children, strength = 0.4, radius = 120 }) {
  const ref = useRef(null)

  useEffect(() => {
    const el = ref.current

    function onMove(e) {
      const rect = el.getBoundingClientRect()
      const cx = rect.left + rect.width / 2
      const cy = rect.top + rect.height / 2
      const dx = e.clientX - cx
      const dy = e.clientY - cy
      const dist = Math.sqrt(dx * dx + dy * dy)

      if (dist < radius) {
        gsap.to(el, {
          x: dx * strength,
          y: dy * strength,
          duration: 0.3,
          ease: 'power2.out'
        })
      } else {
        gsap.to(el, {
          x: 0, y: 0,
          duration: 0.6,
          ease: 'elastic.out(1, 0.3)'
        })
      }
    }

    window.addEventListener('mousemove', onMove)
    el.addEventListener('mouseleave', () =>
      gsap.to(el, { x: 0, y: 0, duration: 0.6, ease: 'elastic.out(1, 0.3)' })
    )
    return () => window.removeEventListener('mousemove', onMove)
  }, [strength, radius])

  return <div ref={ref} style={{ display: 'inline-block', willChange: 'transform' }}>{children}</div>
}

// Usage — wrap any element:
<Magnetic strength={0.4} radius={120}>
  <button>Get Started →</button>
</Magnetic>
